 592→/**
 593→ * 下载进度卡片组件
 594→ */
 595→@Composable
 596→private fun DownloadProgressCard(
 597→    task: DownloadTask,
 598→    onCancel: () -> Unit,
 599→    formatFileSize: (Long) -> String,
 600→    formatSpeed: (Long) -> String,
 601→    formatRemainingTime: (Long) -> String,
 602→    getStatusText: (DownloadStatus) -> String
 603→) {
 604→    Card(
 605→        modifier = Modifier.fillMaxWidth(),
 606→        colors = CardDefaults.cardColors(
 607→            containerColor = when (task.status) {
 608→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
 609→                DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.tertiaryContainer
 610→                else -> MaterialTheme.colorScheme.primaryContainer
 611→            }
 612→        )
 613→    ) {
 614→        Column(modifier = Modifier.padding(16.dp)) {
 615→            // 标题和状态
 616→            Row(
 617→                modifier = Modifier.fillMaxWidth(),
 618→                horizontalArrangement = Arrangement.SpaceBetween,
 619→                verticalAlignment = Alignment.CenterVertically
 620→            ) {
 621→                Column(Modifier.weight(1f)) {
 622→                    Text(
 623→                        task.title,
 624→                        style = MaterialTheme.typography.titleSmall,
 625→                        maxLines = 1,
 626→                        overflow = TextOverflow.Ellipsis
 627→                    )
 628→                    Text(
 629→                        getStatusText(task.status),
 630→                        style = MaterialTheme.typography.bodySmall,
 631→                        color = when (task.status) {
 632→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
 633→                            DownloadStatus.WAITING_FOR_AUTH -> MaterialTheme.colorScheme.onTertiaryContainer
 634→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
 635→                        }
 636→                    )
 637→                }
 638→
 639→                // 取消按钮
 640→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
 641→                    IconButton(onClick = onCancel) {
 642→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
 643→                    }
 644→                }
 645→            }
 646→
 647→            Spacer(Modifier.height(12.dp))
 648→
 649→            // 进度条
 650→            if (task.status == DownloadStatus.DOWNLOADING) {
 651→                Column {
 652→                    Row(
 653→                        modifier = Modifier.fillMaxWidth(),
 654→                        horizontalArrangement = Arrangement.SpaceBetween
 655→                    ) {
 656→                        Text(
 657→                            "${task.progress}%",
 658→                            style = MaterialTheme.typography.bodySmall
 659→                        )
 660→                        if (task.speed > 0) {
 661→                            Text(
 662→                                formatSpeed(task.speed),
 663→                                style = MaterialTheme.typography.bodySmall,
 664→                                color = MaterialTheme.colorScheme.primary
 665→                            )
 666→                        }
 667→                    }
 668→
 669→                    Spacer(Modifier.height(4.dp))
 670→
 671→                    LinearProgressIndicator(
 672→                        progress = { task.progress / 100f },
 673→                        modifier = Modifier.fillMaxWidth(),
 674→                        color = MaterialTheme.colorScheme.primary
 675→                    )
 676→
 677→                    // 文件大小和剩余时间
 678→                    if (task.totalBytes > 0) {
 679→                        Spacer(Modifier.height(4.dp))
 680→                        Row(
 681→                            modifier = Modifier.fillMaxWidth(),
 682→                            horizontalArrangement = Arrangement.SpaceBetween
 683→                        ) {
 684→                            Text(
 685→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
 686→                                style = MaterialTheme.typography.bodySmall,
 687→                                color = MaterialTheme.colorScheme.onPrimaryContainer
 688→                            )
 689→                            if (task.remainingTime > 0 && task.speed > 0) {
 690→                                Text(
 691→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
 692→                                    style = MaterialTheme.typography.bodySmall,
 693→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
 694→                                )
 695→                            }
 696→                        }
 697→                    }
 698→                }
 699→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
 700→                Row(
 701→                    modifier = Modifier.fillMaxWidth(),
 702→                    verticalAlignment = Alignment.CenterVertically
 703→                ) {
 704→                    CircularProgressIndicator(
 705→                        modifier = Modifier.size(20.dp),
 706→                        strokeWidth = 2.dp
 707→                    )
 708→                    Spacer(Modifier.width(8.dp))
 709→                    Text(
 710→                        "正在解析视频信息...",
 711→                        style = MaterialTheme.typography.bodySmall,
 712→                        color = MaterialTheme.colorScheme.onPrimaryContainer
 713→                    )
 714→                }
 715→            } else if (task.status == DownloadStatus.FAILED) {
 716→                Row(
 717→                    modifier = Modifier.fillMaxWidth(),
 718→                    verticalAlignment = Alignment.CenterVertically
 719→                ) {
 720→                    Icon(
 721→                        Icons.Default.Error,
 722→                        contentDescription = null,
 723→                        tint = MaterialTheme.colorScheme.error,
 724→                        modifier = Modifier.size(20.dp)
 725→                    )
 726→                    Spacer(Modifier.width(8.dp))
 727→                    Text(
 728→                        task.errorMessage ?: "下载失败",
 729→                        style = MaterialTheme.typography.bodySmall,
 730→                        color = MaterialTheme.colorScheme.error
 731→                    )
 732→                }
 733→            } else if (task.status == DownloadStatus.COMPLETED) {
 734→                Row(
 735→                    modifier = Modifier.fillMaxWidth(),
 736→                    verticalAlignment = Alignment.CenterVertically
 737→                ) {
 738→                    Icon(
 739→                        Icons.Default.CheckCircle,
 740→                        contentDescription = null,
 741→                        tint = MaterialTheme.colorScheme.primary,
 742→                        modifier = Modifier.size(20.dp)
 743→                    )
 744→                    Spacer(Modifier.width(8.dp))
 745→                    Text(
 746→                        "下载完成",
 747→                        style = MaterialTheme.typography.bodySmall,
 748→                        color = MaterialTheme.colorScheme.primary
 749→                    )
 750→                }
 751→            } else if (task.status == DownloadStatus.WAITING_FOR_AUTH) {
 752→                Row(
 753→                    modifier = Modifier.fillMaxWidth(),
 754→                    verticalAlignment = Alignment.CenterVertically
 755→                ) {
 756→                    Icon(
 757→                        Icons.Default.Lock,
 758→                        contentDescription = null,
 759→                        tint = MaterialTheme.colorScheme.tertiary,
 760→                        modifier = Modifier.size(20.dp)
 761→                    )
 762→                    Spacer(Modifier.width(8.dp))
 763→                    Text(
 764→                        "需要登录获取下载权限",
 765→                        style = MaterialTheme.typography.bodySmall,
 766→                        color = MaterialTheme.colorScheme.onTertiaryContainer
 767→                    )
 768→                }
 769→            }
 770→        }
 771→    }
 772→}
