185→    fun downloadVideo(onComplete: (String, String?) -> Unit) {
186→        val url = _uiState.value.url.trim()
187→
188→        if (url.isBlank()) {
189→            // 不再使用 currentDownload，直接在 activeDownloads 中添加错误任务
190→            return
191→        }
192→
193→        // 检查是否已存在相同视频（通过 URL 匹配）
194→        val existingVideo = _uiState.value.videos.find { it.sourceUrl == url }
195→        if (existingVideo != null) {
196→            // 显示重复下载确认对话框
197→            _uiState.update { it.copy(
198→                showDuplicateDownloadConfirm = true,
199→                duplicateVideoTitle = existingVideo.title
200→            )}
201→            return
202→        }
203→
204→        // 如果已达最大并发数，加入队列
205→        if (activeDownloadTasks.size >= MAX_CONCURRENT_DOWNLOADS) {
206→            addToQueue(url)
207→            return
208→        }
209→
210→        startDownload(url, onComplete)
211→    }
