239→    /**
240→     * 开始下载
241→     */
242→    private fun startDownload(url: String, onComplete: (String, String?) -> Unit) {
243→        lateinit var job: Job
244→        job = viewModelScope.launch(Dispatchers.IO) {
245→            // 创建下载任务
246→            val task = DownloadTask(
247→                url = url,
248→                title = "正在解析...",
249→                status = DownloadStatus.FETCHING_INFO
250→            )
251→
252→            try {
253→                // 添加到活跃下载
254→                activeDownloadTasks[task.id] = task
255→                // 保存当前 job 到 Map（需要在协程启动后）
256→                activeDownloadJobs[task.id] = job
257→                updateActiveDownloads()
258→
259→                // 获取视频信息
260→                val result = videoDownloadService.getVideoInfo(url)
261→
262→                result.onSuccess { videoInfo ->
263→                    // 检查是否需要Cookie但未配置
264→                    val needsCookie = when (videoInfo.platform) {
265→                        VideoDownloadService.VideoPlatform.BILIBILI -> true
266→                        VideoDownloadService.VideoPlatform.YOUTUBE -> false  // YouTube通常不需要Cookie
267→                        VideoDownloadService.VideoPlatform.DOUYIN -> false  // 抖音使用API解析
268→                        VideoDownloadService.VideoPlatform.TIKTOK -> false  // TikTok使用API解析
269→                        else -> false
270→                    }
271→
272→                    val hasCookie = when (videoInfo.platform) {
273→                        VideoDownloadService.VideoPlatform.BILIBILI -> videoDownloadService.hasBilibiliCookie()
274→                        VideoDownloadService.VideoPlatform.YOUTUBE -> videoDownloadService.hasYouTubeCookie()
275→                        VideoDownloadService.VideoPlatform.DOUYIN -> videoDownloadService.hasDouyinCookie()
276→                        VideoDownloadService.VideoPlatform.TIKTOK -> videoDownloadService.hasTiktokCookie()
277→                        else -> true
278→                    }
279→
280→                    if (needsCookie && !hasCookie) {
281→                        // 需要登录获取Cookie，根据平台显示不同的登录对话框
282→                        // 先添加一个等待认证的任务到 activeDownloads
283→                        val waitingTask = task.copy(
284→                            title = "需要登录",
285→                            status = DownloadStatus.WAITING_FOR_AUTH
286→                        )
287→                        activeDownloadTasks[task.id] = waitingTask
288→                        updateActiveDownloads()
289→
290→                        when (videoInfo.platform) {
291→                            VideoDownloadService.VideoPlatform.BILIBILI -> {
292→                                _uiState.update {
293→                                    it.copy(
294→                                        showBilibiliLogin = true,
295→                                        pendingDownloadUrl = url
296→                                    )
297→                                }
298→                            }
299→                            VideoDownloadService.VideoPlatform.YOUTUBE -> {
300→                                _uiState.update {
301→                                    it.copy(
302→                                        showYouTubeLogin = true,
303→                                        pendingDownloadUrl = url
304→                                    )
305→                                }
306→                            }
307→                            VideoDownloadService.VideoPlatform.DOUYIN -> {
308→                                _uiState.update {
309→                                    it.copy(
310→                                        showDouyinLogin = true,
311→                                        pendingDownloadUrl = url
312→                                    )
313→                                }
314→                            }
315→                            VideoDownloadService.VideoPlatform.TIKTOK -> {
316→                                _uiState.update {
317→                                    it.copy(
318→                                        showTiktokLogin = true,
319→                                        pendingDownloadUrl = url
320→                                    )
321→                                }
322→                            }
323→                            else -> { /* 不应该到达这里 */ }
324→                        }
325→                        return@launch
326→                    }
327→
328→                    // 更新任务信息并显示在 activeDownloads 中
329→                    val updatedTask = task.copy(
330→                        title = videoInfo.title,
331→                        status = DownloadStatus.DOWNLOADING
332→                    )
333→                    activeDownloadTasks[task.id] = updatedTask
334→                    updateActiveDownloads()
335→
336→                    // 生成文件名
337→                    val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
338→                    val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")
339→
340→                    // 使用分段下载器下载，传递Cookie和taskId
341→                    downloadWithSegmentedDownloader(task.id, url, videoInfo, safeTitle, outputFile, onComplete)
342→                }.onFailure { error ->
343→                    val failedTask = task.copy(
344→                        status = DownloadStatus.FAILED,
345→                        errorMessage = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频",
346→                        errorCode = error.javaClass.simpleName
347→                    )
348→                    onDownloadFailed(task.id, failedTask, failedTask.errorMessage ?: "解析失败")
349→                }

