            if (uiState.enableCookieAuth) {
                Spacer(Modifier.height(16.dp))

                // B站Cookie配置
                Text("B站Cookie配置", style = MaterialTheme.typography.titleMedium)

                Spacer(Modifier.height(8.dp))

                // SESSDATA (必填)
                var showSessdata by remember { mutableStateOf(false) }
                OutlinedTextField(
                    value = uiState.bilibiliSessdata,
                    onValueChange = viewModel::setBilibiliSessdata,
                    label = { Text("SESSDATA (必填)") },
                    placeholder = { Text("从浏览器Cookie中复制") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true,
                    visualTransformation = if (showSessdata) {
                        androidx.compose.ui.text.input.VisualTransformation.None
                    } else {
                        PasswordVisualTransformation()
                    },
                    trailingIcon = {
                        Row(
                            modifier = Modifier.padding(end = 8.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            // 自动获取按钮
                            TextButton(
                                onClick = { showBilibiliLogin = true },
                                modifier = Modifier.padding(end = 4.dp),
                                contentPadding = PaddingValues(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Icon(
                                    Icons.Default.CloudDownload,
                                    contentDescription = null,
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(Modifier.width(4.dp))
                                Text("自动获取", style = MaterialTheme.typography.labelSmall)
                            }
                            IconButton(onClick = { showSessdata = !showSessdata }) {
                                Icon(
