                                )
                            }
                        }
                    }
                )

                Spacer(Modifier.height(8.dp))

                // bili_jct (可选)
                var showBiliJct by remember { mutableStateOf(false) }
                OutlinedTextField(
                    value = uiState.bilibiliBiliJct,
                    onValueChange = viewModel::setBilibiliBiliJct,
                    label = { Text("bili_jct (可选)") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true,
                    visualTransformation = if (showBiliJct) {
                        androidx.compose.ui.text.input.VisualTransformation.None
                    } else {
                        PasswordVisualTransformation()
                    },
                    trailingIcon = {
                        IconButton(onClick = { showBiliJct = !showBiliJct }) {
                            Icon(
                                if (showBiliJct) Icons.Default.VisibilityOff
                                else Icons.Default.Visibility,
                                "显示/隐藏"
                            )
                        }
                    }
                )

                Spacer(Modifier.height(8.dp))

                // DedeUserID (可选)
                OutlinedTextField(
                    value = uiState.bilibiliDedeuserid,
                    onValueChange = viewModel::setBilibiliDedeuserid,
                    label = { Text("DedeUserID (可选)") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true
                )

                Spacer(Modifier.height(12.dp))

                // Cookie状态提示
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = if (uiState.hasValidCookie) {
                            MaterialTheme.colorScheme.primaryContainer
                        } else {
                            MaterialTheme.colorScheme.errorContainer
                        }
                    )
                ) {
                    Row(
                        modifier = Modifier.padding(12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            if (uiState.hasValidCookie) Icons.Default.CheckCircle
                            else Icons.Default.Warning,
                            contentDescription = null,
                            tint = if (uiState.hasValidCookie) {
                                MaterialTheme.colorScheme.primary
                            } else {
                                MaterialTheme.colorScheme.error
                            },
                            modifier = Modifier.size(20.dp)
                        )
