package com.multilanglearner.data.store

import android.content.Context
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map
import javax.inject.Inject
import javax.inject.Singleton

private val Context.themeDataStore by preferencesDataStore(name = "theme_prefs")

@Singleton
class ThemeStore @Inject constructor(@ApplicationContext private val context: Context) {
    private val THEME = stringPreferencesKey("theme")
    private val FONT_SIZE = stringPreferencesKey("fontSize")

    val theme: Flow<String> = context.themeDataStore.data.map { it[THEME] ?: "aurora" }
    val fontSize: Flow<String> = context.themeDataStore.data.map { it[FONT_SIZE] ?: "medium" }

    suspend fun setTheme(theme: String) {
        context.themeDataStore.edit { it[THEME] = theme }
    }

    suspend fun setFontSize(size: String) {
        context.themeDataStore.edit { it[FONT_SIZE] = size }
    }
}

