    /**
     * 下载视频 - 支持 B站、YouTube 等平台
     * 支持最多3个并发下载
     */
    fun downloadVideo(onComplete: (String, String?) -> Unit) {
        val url = _uiState.value.url.trim()

        if (url.isBlank()) {
            // 不再使用 currentDownload，直接在 activeDownloads 中添加错误任务
            return
        }

        // 检查是否已存在相同视频（通过 URL 匹配）
        val existingVideo = _uiState.value.videos.find { it.sourceUrl == url }
        if (existingVideo != null) {
            // 显示重复下载确认对话框
            _uiState.update { it.copy(
                showDuplicateDownloadConfirm = true,
                duplicateVideoTitle = existingVideo.title
            )}
            return
        }

        // 如果已达最大并发数，加入队列
        if (activeDownloadTasks.size >= MAX_CONCURRENT_DOWNLOADS) {
            addToQueue(url)
            return
        }

        startDownload(url, onComplete)
    }

    /**
     * 确认重复下载
     */
    fun confirmDuplicateDownload(onComplete: (String, String?) -> Unit) {
        _uiState.update { it.copy(showDuplicateDownloadConfirm = false) }
        val url = _uiState.value.url.trim()

        // 如果已达最大并发数，加入队列
        if (activeDownloadTasks.size >= MAX_CONCURRENT_DOWNLOADS) {
            addToQueue(url)
            return
        }

        startDownload(url, onComplete)
    }

    /**
     * 取消重复下载
     */
    fun cancelDuplicateDownload() {
        _uiState.update { it.copy(
            showDuplicateDownloadConfirm = false,
            duplicateVideoTitle = ""
        )}
    }

    /**
     * 开始下载
     */
    private fun startDownload(url: String, onComplete: (String, String?) -> Unit) {
        lateinit var job: Job
        job = viewModelScope.launch(Dispatchers.IO) {
            // 创建下载任务
            val task = DownloadTask(
                url = url,
                title = "正在解析...",
                status = DownloadStatus.FETCHING_INFO
            )

            try {
                // 添加到活跃下载
                activeDownloadTasks[task.id] = task
                // 保存当前 job 到 Map（需要在协程启动后）
                activeDownloadJobs[task.id] = job
                updateActiveDownloads()

                // 获取视频信息
                val result = videoDownloadService.getVideoInfo(url)

                result.onSuccess { videoInfo ->
                    // 检查是否需要Cookie但未配置
                    val needsCookie = when (videoInfo.platform) {
                        VideoDownloadService.VideoPlatform.BILIBILI -> true
                        VideoDownloadService.VideoPlatform.YOUTUBE -> false  // YouTube通常不需要Cookie
                        VideoDownloadService.VideoPlatform.DOUYIN -> false  // 抖音使用API解析
                        VideoDownloadService.VideoPlatform.TIKTOK -> false  // TikTok使用API解析
                        else -> false
                    }

                    val hasCookie = when (videoInfo.platform) {
                        VideoDownloadService.VideoPlatform.BILIBILI -> videoDownloadService.hasBilibiliCookie()
                        VideoDownloadService.VideoPlatform.YOUTUBE -> videoDownloadService.hasYouTubeCookie()
                        VideoDownloadService.VideoPlatform.DOUYIN -> videoDownloadService.hasDouyinCookie()
                        VideoDownloadService.VideoPlatform.TIKTOK -> videoDownloadService.hasTiktokCookie()
                        else -> true
                    }

                    if (needsCookie && !hasCookie) {
                        // 需要登录获取Cookie，根据平台显示不同的登录对话框
                        // 先添加一个等待认证的任务到 activeDownloads
                        val waitingTask = task.copy(
                            title = "需要登录",
                            status = DownloadStatus.WAITING_FOR_AUTH
                        )
                        activeDownloadTasks[task.id] = waitingTask
                        updateActiveDownloads()

                        when (videoInfo.platform) {
                            VideoDownloadService.VideoPlatform.BILIBILI -> {
                                _uiState.update {
                                    it.copy(
                                        showBilibiliLogin = true,
                                        pendingDownloadUrl = url
                                    )
                                }
                            }
                            VideoDownloadService.VideoPlatform.YOUTUBE -> {
                                _uiState.update {
                                    it.copy(
                                        showYouTubeLogin = true,
                                        pendingDownloadUrl = url
                                    )
                                }
                            }
                            VideoDownloadService.VideoPlatform.DOUYIN -> {
                                _uiState.update {
                                    it.copy(
                                        showDouyinLogin = true,
                                        pendingDownloadUrl = url
                                    )
                                }
                            }
                            VideoDownloadService.VideoPlatform.TIKTOK -> {
                                _uiState.update {
                                    it.copy(
                                        showTiktokLogin = true,
                                        pendingDownloadUrl = url
                                    )
                                }
                            }
                            else -> { /* 不应该到达这里 */ }
                        }
                        return@launch
                    }

                    // 更新任务信息并显示在 activeDownloads 中
                    val updatedTask = task.copy(
                        title = videoInfo.title,
                        status = DownloadStatus.DOWNLOADING
                    )
                    activeDownloadTasks[task.id] = updatedTask
                    updateActiveDownloads()

                    // 生成文件名
                    val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                    val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")

                    // 使用分段下载器下载，传递Cookie和taskId
                    downloadWithSegmentedDownloader(task.id, url, videoInfo, safeTitle, outputFile, onComplete)
                }.onFailure { error ->
                    val failedTask = task.copy(
                        status = DownloadStatus.FAILED,
                        errorMessage = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频",
                        errorCode = error.javaClass.simpleName
                    )
                    onDownloadFailed(task.id, failedTask, failedTask.errorMessage ?: "解析失败")
                }

            } catch (e: Exception) {
                android.util.Log.e("HomeViewModel", "Download failed", e)
                val failedTask = task.copy(
                    status = DownloadStatus.FAILED,
                    errorMessage = "下载失败: ${e.message}",
                    errorCode = e.javaClass.simpleName
                )
                onDownloadFailed(task.id, failedTask, failedTask.errorMessage ?: "下载失败")
            }
        }
    }

    /**
     * 使用分段下载器下载视频
     */
    private suspend fun downloadWithSegmentedDownloader(
        taskId: String,
        url: String,
        videoInfo: com.multilanglearner.data.network.VideoDownloadService.VideoDownloadInfo,
        title: String,
        outputFile: File,
        onComplete: (String, String?) -> Unit
    ) {
        val startTime = System.currentTimeMillis()
        var lastUpdate = startTime

        try {
            val config = SegmentedDownloader.DownloadConfig(
                url = videoInfo.downloadUrl,
                outputFile = outputFile,
                enableResume = true,
                // 使用当前配置的Cookie（如果可用）
                cookies = currentBilibiliCookie ?: videoInfo.cookies,
                // 音频流URL（用于DASH格式）
                audioUrl = videoInfo.audioUrl,
                onProgress = { progress ->
                    val now = System.currentTimeMillis()
                    // 限制更新频率（每200ms更新一次）
                    if (now - lastUpdate > 200) {
                        val elapsedSeconds = (now - startTime) / 1000.0
                        val speed = progress.speed
                        val remainingBytes = progress.totalBytes - progress.bytesDownloaded
                        val remainingTime = if (speed > 0) remainingBytes / speed else 0L

                        // 直接使用 taskId 更新对应的任务进度
                        val currentTask = activeDownloadTasks[taskId]
                        if (currentTask != null) {
                            val updatedTask = currentTask.copy(
                                status = DownloadStatus.DOWNLOADING,
                                progress = progress.percent,
                                bytesDownloaded = progress.bytesDownloaded,
                                totalBytes = progress.totalBytes,
                                speed = speed,
                                remainingTime = remainingTime,
                                title = currentTask.title ?: title
                            )
                            updateActiveDownloadTask(taskId, updatedTask)
                        }
                        lastUpdate = now
                    }
                }
            )

            val result = segmentedDownloader.download(config)

            result.onSuccess { file ->
                // 直接使用传入的 taskId
                val currentTask = activeDownloadTasks[taskId]
                if (currentTask != null) {
                    val completedTask = currentTask.copy(
                        status = DownloadStatus.COMPLETED,
                        progress = 100,
                        completedAt = System.currentTimeMillis()
                    )
                    onDownloadCompleted(taskId, completedTask, file, onComplete)
                }
            }.onFailure { error ->
                // 直接使用传入的 taskId
                val currentTask = activeDownloadTasks[taskId]
                if (currentTask != null) {
                    onDownloadFailed(taskId, currentTask, "下载失败: ${error.message}")
                }
            }

        } catch (e: Exception) {
            android.util.Log.e("HomeViewModel", "Segmented download failed", e)
            // 这里不需要额外处理，因为 onFailure 已经处理了
        }
    }

    /**
     * 取消当前下载
     */
    fun cancelDownload(taskId: String? = null) {
        if (taskId != null) {
            // 取消特定任务 - 直接删除，不保留记录
            activeDownloadJobs[taskId]?.cancel()
            activeDownloadTasks[taskId]?.let { task ->
                activeDownloadTasks.remove(taskId)
                activeDownloadJobs.remove(taskId)
                updateActiveDownloads()

                // 清理临时文件
                if (task.totalBytes > 0) {
                    val safeTitle = task.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                    val outputFile = File(downloadsDir, "${safeTitle}_${task.createdAt}.mp4")
                    segmentedDownloader.cancelDownload(outputFile)
                }
            }
            // 处理队列中的下一个任务
            processQueue()
        } else {
            // 取消所有任务 - 直接删除，不保留记录
            activeDownloadJobs.values.forEach { it.cancel() }
            activeDownloadTasks.values.forEach { task ->
                // 清理临时文件
                if (task.totalBytes > 0) {
                    val safeTitle = task.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                    val outputFile = File(downloadsDir, "${safeTitle}_${task.createdAt}.mp4")
                    segmentedDownloader.cancelDownload(outputFile)
                }
            }
            activeDownloadJobs.clear()
            activeDownloadTasks.clear()
            updateActiveDownloads()
        }
    }

