package com.multilanglearner.data.network

import android.util.Log
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.coroutineScope
import kotlinx.coroutines.delay
import kotlinx.coroutines.withContext
import kotlinx.coroutines.withTimeout
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONObject
import java.io.IOException
import java.util.concurrent.TimeUnit
import java.util.concurrent.ConcurrentHashMap

/**
 * 视频下载服务 - 使用在线 API 解析视频
 * 支持多平台：B站、抖音、YouTube、TikTok 等
 *
 * 改进点：
 * - 参考 Electron 版本的平台检测和视频提取逻辑
 * - 改进 B站、抖音的解析逻辑，支持多种备用 API
 * - 添加 YouTube 支持（使用 yt-dlp API 或备用方案）
 * - 改进错误处理和重试机制
 * - 添加详细的日志输出
 * - 支持Cookie认证（解决403问题）
 */
class VideoDownloadService(
    private val bilibiliCookieProvider: (() -> String?)? = null,
    private val youtubeCookieProvider: (() -> String?)? = null,
    private val douyinCookieProvider: (() -> String?)? = null,
    private val tiktokCookieProvider: (() -> String?)? = null
) {

    companion object {
        private const val TAG = "VideoDownloadService"
        private const val DEFAULT_TIMEOUT = 30_000L
        private const val MAX_RETRIES = 3
        private const val RETRY_DELAY_MS = 1000L

        // API 健康检查缓存
        private val apiHealthCache = ConcurrentHashMap<String, ApiHealthStatus>()
        private const val HEALTH_CACHE_DURATION = 5 * 60 * 1000L // 5分钟

        /**
         * API 健康状态数据类
         */
        data class ApiHealthStatus(
            val isAvailable: Boolean,
            val responseTime: Long,
            val lastCheckTime: Long,
            val errorMessage: String? = null
        )

        /**
         * 检查 API 健康状态
         * @param apiUrl API 端点 URL
         * @return 如果缓存有效且 API 可用返回 true，否则返回 true（默认可用，需实际检测）
         */
        fun isApiHealthy(apiUrl: String): Boolean {
            val cached = apiHealthCache[apiUrl]
            if (cached != null && System.currentTimeMillis() - cached.lastCheckTime < HEALTH_CACHE_DURATION) {
                return cached.isAvailable
            }
            return true // 没有缓存时默认可用
        }

        /**
         * 更新 API 健康状态
         * @param apiUrl API 端点 URL
         * @param isAvailable 是否可用
         * @param responseTime 响应时间（毫秒）
         * @param error 错误信息（可选）
         */
        fun updateApiHealth(apiUrl: String, isAvailable: Boolean, responseTime: Long = 0, error: String? = null) {
            apiHealthCache[apiUrl] = ApiHealthStatus(isAvailable, responseTime, System.currentTimeMillis(), error)
            Log.d(TAG, "API health updated: $apiUrl -> available=$isAvailable, responseTime=${responseTime}ms")
        }

        /**
         * 获取最佳 API（按响应时间排序，优先使用最快的可用 API）
         * @param apis API 配置列表
         * @param getUrl 从配置中获取 URL 的函数
         * @return 排序后的 API 列表
         */
        fun <T> getBestApi(apis: List<T>, getUrl: (T) -> String): List<T> {
            return apis.sortedBy { api ->
                val url = getUrl(api)
                val status = apiHealthCache[url]
                if (status == null) 0L else if (status.isAvailable) status.responseTime else Long.MAX_VALUE
            }
        }

        /**
         * 清除过期的健康检查缓存
         */
        fun clearExpiredHealthCache() {
            val now = System.currentTimeMillis()
            apiHealthCache.entries.removeIf { now - it.value.lastCheckTime > HEALTH_CACHE_DURATION }
        }

        /**
         * 获取所有 API 的健康状态（用于调试）
         */
        fun getApiHealthStats(): Map<String, ApiHealthStatus> {
            return apiHealthCache.toMap()
        }
    }

    /**
     * 获取平台对应的Cookie
     */
    private fun getCookieForPlatform(url: String): String? {
        return when {
            url.contains("bilibili.com") || url.contains("b23.tv") -> bilibiliCookieProvider?.invoke()
            url.contains("youtube.com") || url.contains("youtu.be") -> youtubeCookieProvider?.invoke()
            url.contains("douyin.com") || url.contains("iesdouyin.com") -> douyinCookieProvider?.invoke()
            url.contains("tiktok.com") -> tiktokCookieProvider?.invoke()
            else -> null
        }
    }

    /**
     * 检查指定URL是否需要Cookie认证
     */
    fun isCookieRequired(url: String): Boolean {
        return when {
            url.contains("bilibili.com") || url.contains("b23.tv") -> bilibiliCookieProvider?.invoke()?.isNotBlank() == true
            url.contains("youtube.com") || url.contains("youtu.be") -> youtubeCookieProvider?.invoke()?.isNotBlank() == true
            url.contains("douyin.com") || url.contains("iesdouyin.com") -> douyinCookieProvider?.invoke()?.isNotBlank() == true
            url.contains("tiktok.com") -> tiktokCookieProvider?.invoke()?.isNotBlank() == true
            else -> false
        }
    }

    /**
     * 检查是否已配置B站Cookie
     */
    fun hasBilibiliCookie(): Boolean {
        return bilibiliCookieProvider?.invoke()?.isNotBlank() == true
    }

    /**
     * 检查是否已配置YouTube Cookie
     */
    fun hasYouTubeCookie(): Boolean {
        return youtubeCookieProvider?.invoke()?.isNotBlank() == true
    }

    /**
     * 检查是否已配置抖音 Cookie
     */
    fun hasDouyinCookie(): Boolean {
        return douyinCookieProvider?.invoke()?.isNotBlank() == true
    }

    /**
     * 检查是否已配置TikTok Cookie
     */
    fun hasTiktokCookie(): Boolean {
        return tiktokCookieProvider?.invoke()?.isNotBlank() == true
    }

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .followRedirects(true)
        .build()

    /**
     * 平台检测 - 参考 Electron 版本的 detectPlatform 函数
     * 支持更多平台和短链接
     */
    fun detectPlatform(url: String): VideoPlatform {
        val lowerUrl = url.lowercase()
        return when {
            // YouTube - 支持主域名和短链接
            lowerUrl.contains("youtube.com") || lowerUrl.contains("youtu.be") -> VideoPlatform.YOUTUBE
            // Bilibili - 支持主域名和 b23.tv 短链接
            lowerUrl.contains("bilibili.com") || lowerUrl.contains("b23.tv") -> VideoPlatform.BILIBILI
            // 抖音 - 支持多种域名
            lowerUrl.contains("douyin.com") || lowerUrl.contains("iesdouyin.com") -> VideoPlatform.DOUYIN
            // TikTok
            lowerUrl.contains("tiktok.com") -> VideoPlatform.TIKTOK
            // 微博
            lowerUrl.contains("weibo.com") -> VideoPlatform.WEIBO
            // 小红书
            lowerUrl.contains("xiaohongshu.com") || lowerUrl.contains("xhslink.com") -> VideoPlatform.XIAOHONGSHU
            // 微信视频号
            lowerUrl.contains("channels.weixin.qq.com") ||
            lowerUrl.contains("video.weibo.com/show?fid=1034") ||
            lowerUrl.contains("weixin.qq.com/s/") -> VideoPlatform.WECHAT
            // 直接视频链接
            lowerUrl.contains(".mp4") || lowerUrl.contains(".m3u8") || lowerUrl.contains(".mpd") -> VideoPlatform.DIRECT
            // 未知平台
            else -> VideoPlatform.UNKNOWN
        }
    }

    /**
     * 获取视频下载链接 - 主入口函数
     * 参考 Electron 版本的 extract-info IPC 处理
     */
    suspend fun getVideoInfo(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        withTimeout(DEFAULT_TIMEOUT) {
            try {
                val cleanUrl = cleanUrl(url)
                Log.d(TAG, "Processing URL: $cleanUrl")

                val platform = detectPlatform(cleanUrl)
                Log.d(TAG, "Detected platform: $platform")

                when (platform) {
                    VideoPlatform.YOUTUBE -> fetchYoutubeInfo(cleanUrl)
                    VideoPlatform.BILIBILI -> fetchBilibiliInfo(cleanUrl)
                    VideoPlatform.DOUYIN -> fetchDouyinInfo(cleanUrl)
                    VideoPlatform.TIKTOK -> fetchTiktokInfo(cleanUrl)
                    VideoPlatform.XIAOHONGSHU -> fetchXiaohongshuInfo(cleanUrl)
                    VideoPlatform.WECHAT -> fetchWechatChannelsInfo(cleanUrl)
                    VideoPlatform.DIRECT -> Result.success(
                        VideoDownloadInfo(
                            title = "直接视频链接",
                            downloadUrl = cleanUrl,
                            cover = null,
                            duration = 0L,
                            author = null,
                            platform = VideoPlatform.DIRECT
                        )
                    )
                    else -> Result.failure(
                        Exception(
                            "❌ 不支持的平台\n\n当前链接: $cleanUrl\n\n支持的平台:\n• YouTube (youtube.com, youtu.be)\n• B站 (bilibili.com, b23.tv)\n• 抖音 (douyin.com)\n• TikTok (tiktok.com)\n• 小红书 (xiaohongshu.com, xhslink.com)\n• 微信视频号 (channels.weixin.qq.com)\n\n建议: 请使用「导入本地视频」功能"
                        )
                    )
                }
            } catch (e: Exception) {
                Log.e(TAG, "Error fetching video info", e)
                Result.failure(e)
            }
        }
    }

    /**
     * 清理 URL - 移除多余空格和无效字符
     * 参考 Electron 版本的 cleanUrl 函数
     */
    private fun cleanUrl(url: String): String {
        val trimmed = url.trim()
        // 提取第一个有效的 HTTP/HTTPS 链接
        val match = Regex("(https?://[^\\s\"'<>]+)").find(trimmed)
        return match?.value ?: trimmed
    }

    /**
     * 获取 YouTube 视频信息 - 改进版，使用 InnerTube API
     * 基于 GitHub 研究：
     * - ViMusic: https://github.com/vfsfitvnm/ViMusic (InnerTube 实现)
     * - NewPipeExtractor: https://github.com/TeamNewPipe/NewPipeExtractor
     */
    private suspend fun fetchYoutubeInfo(url: String): Result<VideoDownloadInfo> {
        Log.d(TAG, "Fetching YouTube info for: $url")

        // 策略1: 尝试 NewPipeExtractor（推荐）
        val newPipeResult = fetchYoutubeNewPipe(url)
        if (newPipeResult.isSuccess) {
            Log.d(TAG, "NewPipeExtractor success")
            return newPipeResult
        }
        Log.w(TAG, "NewPipeExtractor failed: ${newPipeResult.exceptionOrNull()?.message}")

        // 策略2: 尝试 InnerTube API（备用）
        val innertubeResult = fetchYouTubeInnerTubeAPI(url)
        if (innertubeResult.isSuccess) {
            Log.d(TAG, "InnerTube API success")
            return innertubeResult
        }
        Log.w(TAG, "InnerTube API failed: ${innertubeResult.exceptionOrNull()?.message}")

        // 策略3: 尝试第三方API（最后备用）
        return fetchYouTubeThirdPartyAPI(url)
    }

    /**
     * 使用 NewPipeExtractor 解析 YouTube 视频
     * 这是专门为 Android 设计的库，不依赖 YouTube API
     */
    private suspend fun fetchYoutubeNewPipe(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val videoId = extractYoutubeVideoId(url)
                ?: return@withContext Result.failure(Exception("无法提取 YouTube 视频 ID"))

            Log.d(TAG, "Using NewPipeExtractor for YouTube: $videoId")

            val streamInfo = org.schabi.newpipe.extractor.stream.StreamInfo.getInfo(
                org.schabi.newpipe.extractor.NewPipe.getService(0),
                url
            )

            // 获取最佳视频流（videoStreams 已经是视频流，无需过滤）
            val videoStream = streamInfo.videoStreams
                .maxByOrNull { it.height ?: 0 }

            // 获取音频流（audioStreams 已经是音频流，无需过滤）
            val audioStream = streamInfo.audioStreams
                .maxByOrNull { it.averageBitrate ?: 0 }

            if (videoStream != null) {
                Result.success(VideoDownloadInfo(
                    title = streamInfo.name ?: "YouTube 视频",
                    downloadUrl = videoStream.url ?: "",
                    cover = streamInfo.thumbnails?.firstOrNull()?.url,
                    duration = streamInfo.duration?.toLong() ?: 0L,
                    author = streamInfo.uploaderName,
                    platform = VideoPlatform.YOUTUBE,
                    audioUrl = audioStream?.url
                ))
            } else {
                Result.failure(Exception("无法获取视频流"))
            }
        } catch (e: Exception) {
            Log.e(TAG, "NewPipeExtractor error", e)
            Result.failure(e)
        }
    }

    /**
     * 使用 YouTube InnerTube API 解析
     * InnerTube 是 YouTube 的内部 RESTful API
     */
    private suspend fun fetchYouTubeInnerTubeAPI(url: String): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val videoId = extractYoutubeVideoId(url)
            if (videoId == null) {
                return@withContext Result.failure(Exception("无法提取视频ID"))
            }
            Log.d(TAG, "YouTube video ID: $videoId")

            // InnerTube API 请求
            val requestBody = JSONObject().apply {
                put("context", JSONObject().apply {
                    put("client", JSONObject().apply {
                        put("clientName", "ANDROID")
                        put("clientVersion", "19.29.37")
                    })
                })
                put("videoId", videoId)
            }.toString()

            val request = Request.Builder()
                .url("https://www.youtube.com/youtubei/v1/player?key=AIzaSyAO_FJ2SlqU8Q4STEHLGCilw_Y9_11qcW8")
                .header("Content-Type", "application/json")
                .header("User-Agent", "com.google.android.youtube/19.29.37")
                .post(requestBody.toRequestBody("application/json".toMediaType()))
                .build()

            val response = client.newCall(request).execute()
            val body = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))
            val json = JSONObject(body)

            val videoDetails = json.optJSONObject("videoDetails")
            val title = videoDetails?.optString("title") ?: "YouTube视频"
            val author = videoDetails?.optString("author") ?: ""
            val lengthSeconds = videoDetails?.optLong("lengthSeconds") ?: 0L

            val streamingData = json.optJSONObject("streamingData")
            val formats = streamingData?.optJSONArray("formats")

            if (formats != null && formats.length() > 0) {
                val format = formats.getJSONObject(0)
                val videoUrl = format.optString("url")
                val thumbnails = videoDetails?.optJSONObject("thumbnail")?.optJSONArray("thumbnails")
                val cover = thumbnails?.optJSONObject(0)?.optString("url") ?: ""

                return@withContext Result.success(VideoDownloadInfo(
                    title = title,
                    downloadUrl = videoUrl,
                    cover = cover,
                    duration = lengthSeconds,
                    author = author,
                    platform = VideoPlatform.YOUTUBE
                ))
            }

            Result.failure(Exception("无法获取视频流"))

        } catch (e: Exception) {
            Log.e(TAG, "InnerTube API error", e)
            Result.failure(e)
        }
    }

