                            cover = json.optString("thumbnail_url"),
                            duration = 0L,
                            author = author,
                            platform = VideoPlatform.YOUTUBE
                        )
                    )
                }
                else -> Result.failure(Exception("未知 API"))
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error fetching YouTube info with ${api.name}", e)
            Result.failure(e)
        }
    }

    /**
     * 提取 B站 BV 号
     * 支持 BV 号和 b23.tv 短链接
     */
    private fun extractBVID(url: String): String? {
        val bvPattern = Regex("(BV[a-zA-Z0-9]{10})")
        val match = bvPattern.find(url)
        return match?.groupValues?.get(1)
    }

    /**
     * 提取 YouTube 视频 ID
     */
    private fun extractYoutubeVideoId(url: String): String? {
        // 支持 youtube.com/watch?v= 和 youtu.be/ 格式
        val patterns = listOf(
            Regex("(?:youtube\\.com/watch\\?v=|youtu\\.be/)([a-zA-Z0-9_-]{11})"),
            Regex("youtube\\.com/embed/([a-zA-Z0-9_-]{11})")
        )

        for (pattern in patterns) {
            val match = pattern.find(url)
            if (match != null) {
                return match.groupValues[1]
            }
        }
        return null
    }

