        // 尝试多个第三方 API
        val apis = listOf(
            WechatApiConfig("https://api.pearktrue.com/api/v1/parse/wechat?url=$url", "pearktrue"),
            // 可以添加更多备用 API
            // WechatApiConfig("https://api.example.com/wechat?url=$url", "example")
        )

        for ((index, api) in apis.withIndex()) {
            try {
                Log.d(TAG, "[${index + 1}/${apis.size}] Trying WeChat API: ${api.name}")
                val result = fetchWechatChannelsInfoWithApi(api)
                if (result.isSuccess) {
                    Log.d(TAG, "Successfully fetched info using: ${api.name}")
                    return result
                }
                Log.w(TAG, "API ${api.name} failed: ${result.exceptionOrNull()?.message}")
            } catch (e: Exception) {
                Log.e(TAG, "API ${api.name} threw exception", e)
            }
        }

        // 如果所有 API 都失败，返回友好错误
        return Result.failure(
            Exception(
                "❌ 微信视频号解析受限\n\n" +
                "由于微信视频号的特殊保护机制，安卓端暂不支持直接解析。\n\n" +
                "推荐方案：\n" +
                "1. 电脑端使用 res-downloader 工具\n" +
                "   https://github.com/putyy/res-downloader\n\n" +
                "2. 使用「导入本地视频」功能\n" +
                "   先在电脑下载后传输到手机\n\n" +
                "3. 录屏方式\n" +
                "   使用系统录屏保存视频"
            )
        )
    }

    /**
     * 使用指定 API 获取微信视频号信息
     */
    private suspend fun fetchWechatChannelsInfoWithApi(api: WechatApiConfig): Result<VideoDownloadInfo> = withContext(Dispatchers.IO) {
        try {
            val request = Request.Builder()
                .url(api.endpoint)
                .header("User-Agent", getUserAgent())
                .header("Referer", "https://channels.weixin.qq.com/")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return@withContext Result.failure(IOException("空响应"))

            Log.d(TAG, "[${api.name}] Response: ${responseBody.take(300)}")

            // 检查是否是HTML
            if (responseBody.trim().startsWith("<!DOCTYPE") || responseBody.trim().startsWith("<html")) {
                return@withContext Result.failure(Exception("API返回HTML，可能已失效"))
            }

            val json = JSONObject(responseBody)

            // 检查响应状态码
            val code = json.optInt("code")
            if (code != 200 && code != 1 && code != 0) {
                val msg = json.optString("msg") ?: json.optString("message") ?: "未知错误"
                return@withContext Result.failure(Exception("API返回错误($code): $msg"))
            }

            // 解析视频数据
            if (json.has("data")) {
                val data = json.getJSONObject("data")

                val videoUrl = data.optString("url")
                    ?: data.optString("video_url")
                    ?: data.optString("play_addr")
                    ?: data.optString("download_addr")
                    ?: data.optString("media_url")

                val title = data.optString("title")
                    ?: data.optString("desc")
                    ?: data.optString("text")
                    ?: data.optString("description")
                    ?: "微信视频号"

                if (videoUrl.isNotEmpty() && videoUrl.startsWith("http")) {
                    return@withContext Result.success(VideoDownloadInfo(
                        title = title,
                        downloadUrl = videoUrl,
                        cover = data.optString("cover")
                            ?: data.optString("thumb")
                            ?: data.optString("thumbnail"),
                        duration = data.optLong("duration", 0L),
                        author = data.optString("author")
                            ?: data.optString("nickname")
                            ?: data.optString("username"),
                        platform = VideoPlatform.WECHAT
                    ))
                }
            }

            // 直接格式
            val directUrl = json.optString("url")
                ?: json.optString("video_url")
                ?: json.optString("media_url")

            if (directUrl.startsWith("http")) {
                return@withContext Result.success(VideoDownloadInfo(
                    title = json.optString("title") ?: json.optString("desc") ?: "微信视频号",
                    downloadUrl = directUrl,
                    cover = json.optString("cover") ?: json.optString("thumb"),
                    duration = json.optLong("duration", 0L),
                    author = json.optString("author") ?: json.optString("nickname"),
                    platform = VideoPlatform.WECHAT
                ))
            }

            Result.failure(Exception("无法从API响应中提取视频链接"))

        } catch (e: Exception) {
            Log.e(TAG, "[${api.name}] Request failed", e)
            Result.failure(e)
        }
    }

    // ==================== API 配置数据类 ====================

    private data class XiaohongshuApiConfig(
        val endpoint: String,
        val name: String
    )

    private data class YoutubeApiConfig(
        val endpoint: String,
        val name: String
    )

    private data class BilibiliApiConfig(
        val endpoint: String,
        val name: String
    )

    private data class DouyinApiConfig(
        val endpoint: String,
        val name: String
    )

    private data class TiktokApiConfig(
        val endpoint: String,
        val name: String
    )

    private data class WechatApiConfig(
        val endpoint: String,
        val name: String
    )

    /**
     * 下载数据类
     */
    data class VideoDownloadInfo(
        val title: String,
        val downloadUrl: String,
        val cover: String? = null,
        val duration: Long = 0,
        val author: String? = null,
        val cookies: String? = null, // 下载时需要的Cookie
        val platform: VideoPlatform = VideoPlatform.UNKNOWN,
        val audioUrl: String? = null // DASH格式的音频流URL
    )

    /**
     * 支持的平台
     */
    enum class VideoPlatform {
        BILIBILI, DOUYIN, TIKTOK, YOUTUBE, WEIBO, XIAOHONGSHU, WECHAT, DIRECT, UNKNOWN
    }
}

